// Simple Face Generator
// Draw a basic face based on parameters

let skinColors = {
  pale: [255, 224, 196],
  light: [241, 194, 125],
  medium: [224, 172, 105],
  tan: [198, 134, 66],
  brown: [141, 85, 36],
  dark: [101, 67, 33]
};

let hairColors = {
  black: [40, 40, 40],
  brown: [106, 78, 66],
  blonde: [255, 240, 165],
  red: [165, 42, 42],
  gray: [160, 160, 160],
  white: [250, 250, 250]
};

let eyeColors = {
  brown: [101, 67, 33],
  hazel: [150, 110, 80],
  green: [46, 139, 87],
  blue: [70, 130, 180],
  gray: [120, 120, 120],
  amber: [255, 191, 0]
};

p.setup = function() {
  p.createCanvas(400, 500);
  p.frameRate(30);
};

p.draw = function() {
  p.background(240, 240, 250);

  // Get current values from app (if available)
  let headShape = 'oval';
  let skinTone = 'medium';
  let eyeColor = 'brown';
  let hairStyle = 'short';
  let hairColor = 'brown';
  let noseShape = 'straight';
  let mouthShape = 'full';

  // Try to get values from window.synthSmall if available
  if (typeof window !== 'undefined' && window.synthSmall && window.synthSmall.currentValues) {
    const vals = window.synthSmall.currentValues;
    headShape = vals.head_shape || headShape;
    skinTone = vals.skin_tone || skinTone;
    eyeColor = vals.eye_color || eyeColor;
    hairStyle = vals.hair_style || hairStyle;
    hairColor = vals.hair_color || hairColor;
    noseShape = vals.nose_shape || noseShape;
    mouthShape = vals.mouth_shape || mouthShape;
  }

  p.push();
  p.translate(p.width/2, p.height/2);

  // Neck
  let skin = skinColors[skinTone] || [224, 172, 105];
  p.fill(skin[0], skin[1], skin[2]);
  p.noStroke();
  p.rect(-30, 100, 60, 100);

  // Head
  p.stroke(0, 0, 0, 30);
  p.strokeWeight(2);

  if (headShape === 'oval') {
    p.ellipse(0, 0, 200, 250);
  } else if (headShape === 'round') {
    p.ellipse(0, 0, 220, 220);
  } else if (headShape === 'square') {
    p.rectMode(p.CENTER);
    p.rect(0, 0, 200, 220, 10);
    p.rectMode(p.CORNER);
  } else if (headShape === 'heart') {
    p.ellipse(0, -20, 200, 200);
    p.triangle(-80, 50, 80, 50, 0, 120);
  } else if (headShape === 'diamond') {
    p.quad(0, -120, 100, 0, 0, 120, -100, 0);
  } else {
    p.rect(-90, -110, 180, 240, 10);
  }

  // Hair
  let hair = hairColors[hairColor] || [106, 78, 66];
  p.fill(hair[0], hair[1], hair[2]);

  if (hairStyle !== 'bald') {
    if (hairStyle === 'short') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
    } else if (hairStyle === 'long') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
      p.rect(-105, -60, 80, 180);
      p.rect(25, -60, 80, 180);
    } else if (hairStyle === 'wavy') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
      for (let i = 0; i < 5; i++) {
        p.ellipse(-80 + i * 40, 20, 30, 100);
      }
    } else if (hairStyle === 'curly') {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
      for (let y = 0; y < 3; y++) {
        for (let x = 0; x < 5; x++) {
          p.circle(-80 + x * 40, -40 + y * 40, 35);
        }
      }
    } else {
      p.arc(0, -60, 210, 140, p.PI, p.TWO_PI);
    }
  }

  // Eyes
  let eyes = eyeColors[eyeColor] || [101, 67, 33];
  p.fill(255);
  p.ellipse(-40, -20, 50, 35);
  p.ellipse(40, -20, 50, 35);
  p.fill(eyes[0], eyes[1], eyes[2]);
  p.circle(-40, -20, 25);
  p.circle(40, -20, 25);
  p.fill(0);
  p.circle(-40, -20, 12);
  p.circle(40, -20, 12);

  // Eyebrows
  p.stroke(hair[0] - 20, hair[1] - 20, hair[2] - 20);
  p.strokeWeight(4);
  p.noFill();
  p.arc(-40, -45, 50, 20, p.PI, p.TWO_PI);
  p.arc(40, -45, 50, 20, p.PI, p.TWO_PI);

  // Nose
  p.fill(skin[0] - 15, skin[1] - 15, skin[2] - 15);
  p.noStroke();
  if (noseShape === 'button') {
    p.ellipse(0, 20, 25, 20);
  } else if (noseShape === 'long') {
    p.ellipse(0, 30, 20, 50);
  } else if (noseShape === 'broad') {
    p.ellipse(0, 20, 40, 30);
  } else {
    p.triangle(-10, 0, 10, 0, 0, 40);
  }

  // Mouth
  p.fill(200, 80, 80);
  p.stroke(160, 60, 60);
  p.strokeWeight(2);
  if (mouthShape === 'full') {
    p.arc(0, 70, 60, 40, 0, p.PI);
  } else if (mouthShape === 'thin') {
    p.arc(0, 70, 50, 20, 0, p.PI);
  } else if (mouthShape === 'wide') {
    p.arc(0, 70, 80, 35, 0, p.PI);
  } else if (mouthShape === 'small') {
    p.arc(0, 70, 30, 20, 0, p.PI);
  } else if (mouthShape === 'heart') {
    p.arc(-15, 65, 30, 25, 0, p.PI);
    p.arc(15, 65, 30, 25, 0, p.PI);
  } else {
    p.arc(0, 70, 60, 30, 0, p.PI);
  }

  p.pop();
};
